// 전월 날짜 범위 계산 (KST 기준, n8n 서버는 UTC)
// KST = UTC+9, 매월 1일 21:00 UTC = 다음날 06:00 KST
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth(); // 0-based, 현재 월의 이전 달 = 전월

const targetYear = month === 0 ? year - 1 : year;
const targetMonth = month === 0 ? 12 : month; // 1-based 전월

const startDate = new Date(targetYear, targetMonth - 1, 1);
const endDate = new Date(targetYear, targetMonth, 0); // 전월 마지막 날

const pad = (n) => String(n).padStart(2, '0');
const fmtDate = (d) => `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}`;

return [{
  json: {
    targetYear,
    targetMonth,
    startDate: fmtDate(startDate),
    endDate: fmtDate(endDate),
    startDateDisplay: `${targetYear}-${pad(targetMonth)}-01`,
    endDateDisplay: `${targetYear}-${pad(targetMonth)}-${pad(endDate.getDate())}`
  }
}];

// 메이크샵 주문 전체 조회 + NocoDB 매핑/협회 조회를 순차적으로 수행
// (n8n 병렬 입력 버그 방지 위해 단일 Code 노드에서 모두 처리)
const shopkey = $env.MAKESHOP_SHOPKEY;
const licensekey = $env.MAKESHOP_LICENSEKEY;
const nocoToken = $env.NOCODB_API_TOKEN;
const nocoProjectId = $env.NOCODB_PROJECT_ID;
const dateInfo = $input.first().json;

const startDate = dateInfo.startDate;
const endDate = dateInfo.endDate;

const https = require('https');

// HTTP 요청 헬퍼
function httpGet(hostname, path, headers) {
  return new Promise((resolve, reject) => {
    const options = { hostname, port: 443, path, method: 'GET', headers };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => { data += chunk; });
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch(e) { resolve({ list: [], totalCount: 0 }); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// 1. 메이크샵 주문 조회 (전월 완료 주문)
let allOrders = [];
try {
  const firstPage = await httpGet(
    'foreverlove.co.kr',
    `/list/open_api.html?type=order_list&mode=search&startDate=${startDate}&endDate=${endDate}&pageNum=1&pageSize=100&statusType=complete`,
    { 'Shopkey': shopkey, 'Licensekey': licensekey, 'Content-Type': 'application/json' }
  );
  const totalCount = firstPage.totalCount || firstPage.total_count || (firstPage.list || []).length;
  allOrders = allOrders.concat(firstPage.list || []);

  const totalPages = Math.ceil(totalCount / 100);
  for (let p = 2; p <= Math.min(totalPages, 20); p++) {
    const page = await httpGet(
      'foreverlove.co.kr',
      `/list/open_api.html?type=order_list&mode=search&startDate=${startDate}&endDate=${endDate}&pageNum=${p}&pageSize=100&statusType=complete`,
      { 'Shopkey': shopkey, 'Licensekey': licensekey, 'Content-Type': 'application/json' }
    );
    allOrders = allOrders.concat(page.list || []);
  }
} catch(e) {
  // 메이크샵 API 실패 시 빈 배열로 계속 진행
  allOrders = [];
}

// 2. NocoDB 회원-협회 매핑 조회 (verified=1)
let memberMappings = [];
try {
  const mappingResp = await httpGet(
    'nocodb.pressco21.com',
    `/api/v1/db/data/noco/${nocoProjectId}/mjrgja20gm84e71?where=(verified,eq,1)&limit=1000`,
    { 'xc-token': nocoToken, 'Content-Type': 'application/json' }
  );
  memberMappings = mappingResp.list || [];
} catch(e) {
  memberMappings = [];
}

// 3. NocoDB 협회 마스터 조회 (active)
let affiliations = [];
try {
  const affilResp = await httpGet(
    'nocodb.pressco21.com',
    `/api/v1/db/data/noco/${nocoProjectId}/m1y7q68q1zlrvv6?where=(status,eq,active)&limit=500`,
    { 'xc-token': nocoToken, 'Content-Type': 'application/json' }
  );
  affiliations = affilResp.list || [];
} catch(e) {
  affiliations = [];
}

// 4. 회원ID → 협회코드 맵
const memberToAffil = {};
for (const m of memberMappings) {
  if (m.member_id && m.affiliation_code) {
    memberToAffil[m.member_id] = m.affiliation_code;
  }
}

// 5. 협회코드 → 협회 정보 맵
const affilMap = {};
for (const a of affiliations) {
  affilMap[a.affiliation_code] = a;
}

// 6. 협회별 집계
const affilStats = {};
for (const order of allOrders) {
  // 메이크샵 주문 응답에서 회원 ID 추출 (필드명은 API 응답에 따라 다를 수 있음)
  const memberId = order.member_id || order.memberId || order.user_id || order.userId;
  if (!memberId) continue;

  const affilCode = memberToAffil[memberId];
  if (!affilCode) continue;

  const amount = parseFloat(
    order.totalAmount || order.total_amount || order.orderAmount || order.order_amount || 0
  );
  if (amount <= 0) continue;

  if (!affilStats[affilCode]) {
    affilStats[affilCode] = { affiliation_code: affilCode, total_amount: 0, members: new Set() };
  }
  affilStats[affilCode].total_amount += amount;
  affilStats[affilCode].members.add(memberId);
}

// 7. 결과 배열
const results = Object.values(affilStats).map(stat => ({
  affiliation_code: stat.affiliation_code,
  total_amount: Math.round(stat.total_amount),
  member_count: stat.members.size,
  affilInfo: affilMap[stat.affiliation_code] || null
}));

return [{
  json: {
    targetYear: dateInfo.targetYear,
    targetMonth: dateInfo.targetMonth,
    results,
    totalAffils: results.length,
    orderCount: allOrders.length
  }
}];

// 연간 누적 집계 및 인센티브 레벨 판단 후 NocoDB UPSERT
const data = $input.first().json;
const targetYear = data.targetYear;
const targetMonth = data.targetMonth;
const results = data.results;

const nocoToken = $env.NOCODB_API_TOKEN;
const nocoProjectId = $env.NOCODB_PROJECT_ID;
const TABLE_STATS = 'mdyqit8fhsm7zqu'; // tbl_Affiliation_Stats

const https = require('https');

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const bodyStr = body ? JSON.stringify(body) : null;
    const options = {
      hostname: 'nocodb.pressco21.com',
      port: 443,
      path,
      method,
      headers: {
        'xc-token': nocoToken,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let d = '';
      res.on('data', chunk => { d += chunk; });
      res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

const processed = [];
const incentiveAlerts = [];

for (const result of results) {
  const { affiliation_code, total_amount, member_count, affilInfo } = result;

  // 해당 협회의 올해 전체 월 통계 조회 (누적 계산용)
  const statsPath = `/api/v1/db/data/noco/${nocoProjectId}/${TABLE_STATS}?where=(affiliation_code,eq,${encodeURIComponent(affiliation_code)})~and(year,eq,${targetYear})&limit=12`;
  const existing = await nocoRequest('GET', statsPath, null);
  const existingList = existing.list || [];

  // 이번 달 이전 월 누적합 계산
  let prevCumulative = 0;
  for (const row of existingList) {
    if (row.month < targetMonth) {
      prevCumulative += (row.total_amount || 0);
    }
  }
  const cumulativeAmount = prevCumulative + total_amount;

  // 인센티브 레벨 판단 (협회별 설정값 또는 기본값)
  const t1 = affilInfo ? (affilInfo.target_1 || 5000000) : 5000000;
  const t2 = affilInfo ? (affilInfo.target_2 || 10000000) : 10000000;
  const t3 = affilInfo ? (affilInfo.target_3 || 20000000) : 20000000;
  const inc1 = affilInfo ? (affilInfo.incentive_1 || 250000) : 250000;
  const inc2 = affilInfo ? (affilInfo.incentive_2 || 500000) : 500000;
  const inc3 = affilInfo ? (affilInfo.incentive_3 || 1200000) : 1200000;

  let incentiveLevel = 0;
  let incentiveAmount = 0;
  if (cumulativeAmount >= t3) { incentiveLevel = 3; incentiveAmount = inc3; }
  else if (cumulativeAmount >= t2) { incentiveLevel = 2; incentiveAmount = inc2; }
  else if (cumulativeAmount >= t1) { incentiveLevel = 1; incentiveAmount = inc1; }

  // 이번 달 기존 레코드 확인
  const thisMonthRow = existingList.find(r => r.month === targetMonth);
  const prevLevel = thisMonthRow ? (thisMonthRow.incentive_level || 0) : 0;

  const rowData = {
    affiliation_code,
    year: targetYear,
    month: targetMonth,
    total_amount,
    member_count,
    cumulative_amount: cumulativeAmount,
    incentive_level: incentiveLevel,
    incentive_amount: incentiveAmount,
    incentive_paid: thisMonthRow ? (thisMonthRow.incentive_paid || false) : false,
    updated_at: new Date().toISOString()
  };

  if (thisMonthRow && thisMonthRow.Id) {
    // PATCH (업데이트)
    await nocoRequest(
      'PATCH',
      `/api/v1/db/data/noco/${nocoProjectId}/${TABLE_STATS}/${thisMonthRow.Id}`,
      rowData
    );
  } else {
    // POST (신규 삽입)
    await nocoRequest(
      'POST',
      `/api/v1/db/data/noco/${nocoProjectId}/${TABLE_STATS}`,
      rowData
    );
  }

  processed.push(rowData);

  // 새로 인센티브 레벨 달성 시 알림 대상 추가
  if (incentiveLevel > prevLevel && incentiveLevel > 0) {
    const levelTargets = [t1, t2, t3];
    incentiveAlerts.push({
      affiliation_code,
      affilName: affilInfo ? affilInfo.name : affiliation_code,
      incentiveLevel,
      incentiveAmount,
      cumulativeAmount,
      target: levelTargets[incentiveLevel - 1]
    });
  }
}

return [{
  json: {
    targetYear,
    targetMonth,
    processed,
    incentiveAlerts,
    hasAlerts: incentiveAlerts.length > 0
  }
}];
